+using System.Text.RegularExpressions;
+
+namespace DocSummary.Services;
+
+public partial class DocumentSummaryService
+{
+    private static readonly HashSet<string> StopWords =
+    [
+        "a","an","the","and","or","but","in","on","at","to","for","of","with",
+        "by","from","is","it","its","this","that","are","was","were","be","been",
+        "being","have","has","had","do","does","did","will","would","could",
+        "should","may","might","shall","can","not","no","so","if","then","than",
+        "too","very","just","about","above","after","again","all","also","am",
+        "any","as","because","before","between","both","each","few","he","her",
+        "here","him","his","how","i","into","me","more","most","my","myself",
+        "nor","now","only","other","our","out","over","own","same","she","some",
+        "such","there","these","they","those","through","under","up","us","we",
+        "what","when","where","which","while","who","whom","why","you","your"
+    ];
+
+    /// <summary>
+    /// Produces an extractive summary by scoring sentences based on word frequency.
+    /// </summary>
+    public string Summarize(string documentText, int maxSentences)
+    {
+        var sentences = SplitIntoSentences(documentText);
+
+        if (sentences.Count <= maxSentences)
+            return string.Join(" ", sentences);
+
+        var wordFrequencies = ComputeWordFrequencies(sentences);
+        var scoredSentences = sentences
+            .Select((sentence, index) => (Sentence: sentence, Index: index, Score: ScoreSentence(sentence, wordFrequencies)))
+            .ToList();
+
+        var topSentences = scoredSentences
+            .OrderByDescending(s => s.Score)
+            .Take(maxSentences)
+            .OrderBy(s => s.Index) // preserve original order
+            .Select(s => s.Sentence);
+
+        return string.Join(" ", topSentences);
+    }
+
+    private static List<string> SplitIntoSentences(string text)
+    {
+        return SentenceRegex()
+            .Split(text)
+            .Select(s => s.Trim())
+            .Where(s => s.Length > 0)
+            .ToList();
+    }
+
+    private static Dictionary<string, int> ComputeWordFrequencies(List<string> sentences)
+    {
+        var frequencies = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);
+
+        foreach (var sentence in sentences)
+        {
+            foreach (var word in ExtractWords(sentence))
+            {
+                var lower = word.ToLowerInvariant();
+                if (!StopWords.Contains(lower) && lower.Length > 1)
+                {
+                    frequencies[lower] = frequencies.GetValueOrDefault(lower) + 1;
+                }
+            }
+        }
+
+        return frequencies;
+    }
+
+    private static double ScoreSentence(string sentence, Dictionary<string, int> wordFrequencies)
+    {
+        var words = ExtractWords(sentence);
+        if (words.Count == 0) return 0;
+
+        double score = 0;
+        foreach (var word in words)
+        {
+            score += wordFrequencies.GetValueOrDefault(word.ToLowerInvariant());
+        }
+
+        return score / words.Count;
+    }
+
+    private static List<string> ExtractWords(string text)
+    {
+        return WordRegex()
+            .Matches(text)
+            .Select(m => m.Value)
+            .ToList();
+    }
+
